export function getItemArmorValue(itemType, rarity) {
    const baseArmor = ITEM_ARMOR_VALUES[rarity] || 0;
    const multiplier = ITEM_ARMOR_MULTIPLIERS[itemType] || 1;
    return Math.floor(baseArmor * multiplier);
}
