// 物品因子表（从 ITEM_STATS 读取 dropFactor）
const ITEM_BASE_FACTOR = {};

// 从 ITEM_STATS 中提取 dropFactor
for (const [itemType, stats] of Object.entries(ITEM_STATS)) {
    if (stats.dropFactor !== undefined) {
        ITEM_BASE_FACTOR[itemType] = stats.dropFactor;
    }
}

// 设置默认值
ITEM_BASE_FACTOR["default"] = 0.8;

// 确保所有有 dropFactor 的物品都被正确设置
// 如果没有 dropFactor 的物品，会在 getDropRarityByItem 中使用默认值
export function getDropRarityByItem(itemType, mobRarity) {
    const factor = ITEM_BASE_FACTOR[itemType] || ITEM_BASE_FACTOR["default"];
    const base = RARITY_DROP_RATES[mobRarity];
    if (!base) return "Common";

    // 复制一份，避免修改原对象
    const modifiedBase = { ...base };

    let weights = {};
    let totalWeight = 0;

    // 1. 获取所有可用稀有度
    let availableRarities = Object.keys(modifiedBase).filter(r => modifiedBase[r] > 0);

    // ========== 新增：当 factor < 0.85 时，禁止 Super 掉落 ==========
    const isSuperDisabled = factor < 0.85;

    if (isSuperDisabled && modifiedBase["Super"] !== undefined && modifiedBase["Super"] > 0) {
        const superProb = modifiedBase["Super"];
        // 从可用稀有度中移除 Super
        availableRarities = availableRarities.filter(r => r !== "Super");
        // 将 Super 的概率加到 Ultra 上（不影响 Omega 和 Eternal）
        if (modifiedBase["Ultra"] !== undefined) {
            modifiedBase["Ultra"] = (modifiedBase["Ultra"] || 0) + superProb;
        } else {
            modifiedBase["Ultra"] = superProb;
        }
        // 将 Super 概率设为 0
        modifiedBase["Super"] = 0;
    }
    // =========================================================

    // 2. 核心逻辑：因子越小，越向该生物掉落表的“右侧（高级）”挤压
    availableRarities.forEach((rarity) => {
        const baseProb = modifiedBase[rarity];
        const rarityIndex = RARITY_ORDER.indexOf(rarity);

        // 关键：这里使用 (1 / factor)。
        // 如果 factor = 0.1, 则底数是 10。
        // 稀有度等级越高，权重被放大的倍数就越恐怖。
        let weight = baseProb * Math.pow(1 / factor, rarityIndex);

        weights[rarity] = weight;
        totalWeight += weight;
    });

    // 3. 归一化随机抽奖
    let rand = Math.random() * totalWeight;
    let cumulative = 0;

    for (const rarity of RARITY_ORDER) {
        if (weights[rarity]) {
            cumulative += weights[rarity];
            if (rand <= cumulative) {
                return rarity;
            }
        }
    }

    return availableRarities[0]; // 保底返回
}
// Rarity drop rates
// ===== 🆕 Eternal 掉落特殊处理 =====
function getEternalDropRarity(originalRarity) {
    if (originalRarity !== "Eternal") return { rarity: originalRarity, multiplier: 1 };

    const rand = Math.random();

    // 1% 掉 Mythic，变成 128 个 Mythic
    if (rand < 0.01) {
        return {
            rarity: "Mythic",
            multiplier: 128
        };
    }
    // 94% 掉 Ultra，变成 32 个 Ultra
    else if (rand < 0.95) {
        return {
            rarity: "Ultra",
            multiplier: 32
        };
    }
    // 5% 掉 Super
    else {
        return {
            rarity: "Super",
            multiplier: 1
        };
    }
}

