// ==================== 自动保存系统 ====================
class AutoSaveSystem {
    constructor() {
        this.saveDir = "saves";
        this.autoSaveFile = `${this.saveDir}/autosave.json`;
        this.useGist = false;
        this.gistId = null;

        this.init();
    }

    init() {
        // 检查是否有 Gist ID
        const urlGist = window.URL_PARAMS?.gistId;
        const savedGist = localStorage.getItem('flwrr_last_gist');
        this.gistId = urlGist || savedGist;

        if (this.gistId) {
            this.useGist = true;
            console.log('📦 启用 Gist 云存档:', this.gistId);
        }
    }

    // 🟢 新增：保存到本地
// 在 AutoSaveSystem 类中修改 saveToLocal 方法
    saveToLocal(player, gameData) {
        try {
            // 收集物品数据
            const inventoryItems = [];
            if (player.inventory && player.inventory.items) {
                for (const item of player.inventory.items) {
                    if (item && typeof item.toDict === 'function') {
                        inventoryItems.push(item.toDict());
                    }
                }
            }

            // 收集主栏快捷栏数据
            const quickSlotItems = [];
            if (player.quickSlot && player.quickSlot.slots) {
                for (let i = 0; i < player.quickSlot.slots.length; i++) {
                    const item = player.quickSlot.slots[i];
                    if (item && typeof item.toDict === 'function') {
                        quickSlotItems.push({
                            slot_index: i,
                            ...item.toDict()
                        });
                    }
                }
            }

            // ✅ 新增：收集副栏快捷栏数据
            const secondarySlotItems = [];
            if (player.quickSlot && player.quickSlot.secondarySlots) {
                for (let i = 0; i < player.quickSlot.secondarySlots.length; i++) {
                    const item = player.quickSlot.secondarySlots[i];
                    if (item && typeof item.toDict === 'function') {
                        secondarySlotItems.push({
                            slot_index: i,
                            ...item.toDict()
                        });
                    }
                }
            }

            const saveData = {
                "timestamp": Date.now(),
                "player_data": {
                    "player_rarity": player.playerRarity || "Common",
                    "health": player.health || 100,
                    "max_health": player.maxHealth || 100,
                    "petal_count": player.petalCount || 5,
                    "score": gameData.score || 0,
                    "enemies_killed": gameData.enemiesKilled || 0,
                    "level": player.levelSystem ? player.levelSystem.level : 1,
                    "current_xp": player.levelSystem ? player.levelSystem.currentXp : 0,
                    "total_xp": player.xp || 0,
                    "player_position": {
                        "x": player.physicsBody ? player.physicsBody.position.x : WORLD_WIDTH / 2,
                        "y": player.physicsBody ? player.physicsBody.position.y : WORLD_HEIGHT / 2
                    }
                },
                "inventory": inventoryItems,
                "quick_slot": quickSlotItems,
                "secondary_slot": secondarySlotItems,  // ✅ 新增：保存副栏
                "game_state": {
                    "current_wave": gameData.currentWave || 1,
                    "game_over": gameData.gameOver || false
                },
                "version": "1.0.0",
                "save_type": "autosave"
            };

            localStorage.setItem('autosave', JSON.stringify(saveData));
            return true;
        } catch (error) {
            console.error("[SAVE ERROR] Failed to save game locally:", error);
            return false;
        }
    }



    // 在 AutoSaveSystem 类中修改 loadFromLocal 方法
    loadFromLocal() {
        try {
            const saveDataStr = localStorage.getItem('autosave');
            if (!saveDataStr) {
                console.log("[LOAD] No local save file found");
                return null;
            }

            const saveData = JSON.parse(saveDataStr);

            // ✅ 确保旧存档有 secondary_slot 字段
            if (!saveData.secondary_slot) {
                saveData.secondary_slot = [];
            }

            console.log("[LOAD] Local save loaded");
            return saveData;
        } catch (error) {
            console.error("[LOAD ERROR] Failed to load local save:", error);
            return null;
        }
    }

    async saveGame(player, gameData) {
        // 先保存到本地
        const localSuccess = this.saveToLocal(player, gameData);

        // 如果启用了 Gist，也保存到云端
        if (this.useGist && window.dataManager) {
            try {
                const playerData = this.preparePlayerData(player, gameData);
                await window.dataManager.savePlayerData(player.playerId, playerData);
                console.log('☁️ 云存档保存成功');
            } catch (error) {
                console.error('☁️ 云存档保存失败:', error);
            }
        }

        return localSuccess;
    }

    preparePlayerData(player, gameData) {
        // 收集物品数据
        const inventoryItems = [];
        if (player.inventory && player.inventory.items) {
            for (const item of player.inventory.items) {
                if (item && typeof item.toDict === 'function') {
                    inventoryItems.push(item.toDict());
                }
            }
        }

        const quickSlotItems = [];
        if (player.quickSlot && player.quickSlot.slots) {
            for (let i = 0; i < player.quickSlot.slots.length; i++) {
                const item = player.quickSlot.slots[i];
                if (item && typeof item.toDict === 'function') {
                    quickSlotItems.push({
                        slot_index: i,
                        ...item.toDict()
                    });
                }
            }
        }

        return {
            playerId: player.playerId,
            playerName: player.playerName || 'Unknown',
            lastSave: new Date().toISOString(),
            player_data: {
                level: player.levelSystem?.level || 1,
                health: player.health,
                maxHealth: player.maxHealth,
                xp: player.xp,
                playerRarity: player.playerRarity || "Common",
                position: {
                    x: player.physicsBody?.position?.x || WORLD_WIDTH / 2,
                    y: player.physicsBody?.position?.y || WORLD_HEIGHT / 2
                }
            },
            inventory: inventoryItems,
            quick_slot: quickSlotItems,
            game_data: {
                score: gameData.score || 0,
                enemiesKilled: gameData.enemiesKilled || 0
            }
        };
    }

    async loadGame(player) {
        // 先尝试从本地加载
        const localData = this.loadFromLocal(); // 🟢 现在这个方法存在了

        // 如果启用了 Gist，从云端加载
        if (this.useGist && window.dataManager) {
            try {
                const cloudData = await window.dataManager.loadPlayerData(player.playerId);
                if (cloudData) {
                    console.log('☁️ 从云端加载存档');
                    return this.applyCloudData(player, cloudData);
                }
            } catch (error) {
                console.error('☁️ 云端加载失败，使用本地存档:', error);
            }
        }

        return localData;
    }

    applyCloudData(player, cloudData) {
        // 应用云端数据到玩家
        if (cloudData.player_data) {
            const pd = cloudData.player_data;
            if (player.levelSystem) {
                player.levelSystem.level = pd.level || 1;
                player.xp = pd.xp || 0;
                player.maxHealth = pd.maxHealth || 100;
                player.health = Math.min(pd.health || 100, player.maxHealth);
            }

            if (pd.position && player.physicsBody) {
                player.physicsBody.position.x = pd.position.x || WORLD_WIDTH / 2;
                player.physicsBody.position.y = pd.position.y || WORLD_HEIGHT / 2;
            }
        }

        // 加载背包
        if (cloudData.inventory && player.inventory) {
            try {
                player.inventory.items = [];
                for (const itemData of cloudData.inventory) {
                    if (typeof Item.fromDict === 'function') {
                        const item = Item.fromDict(itemData);
                        player.inventory.items.push(item);
                    }
                }
            } catch (error) {
                console.error('加载背包失败:', error);
            }
        }

        return cloudData.game_data || {};
    }

    hasSaveData() {
        try {
            const saveDataStr = localStorage.getItem('autosave');
            if (!saveDataStr) return false;
            JSON.parse(saveDataStr);
            return true;
        } catch {
            return false;
        }
    }

    getSaveInfo() {
        if (!this.hasSaveData()) {
            return null;
        }

        try {
            const saveDataStr = localStorage.getItem('autosave');
            const saveData = JSON.parse(saveDataStr);

            const timestamp = saveData.timestamp || 0;
            const date = new Date(timestamp);
            const formattedTime = date.toLocaleString();

            const info = {
                "timestamp": timestamp,
                "formatted_time": formattedTime,
                "player_level": saveData.player_data?.level || 1,
                "player_rarity": saveData.player_data?.player_rarity || "Common",
                "score": saveData.player_data?.score || 0,
                "wave": saveData.game_state?.current_wave || 1,
                "inventory_count": saveData.inventory?.length || 0,
                "version": saveData.version || "unknown"
            };

            return info;
        } catch {
            return null;
        }
    }
}

class ChangelogPanel {
    constructor() {
        this.visible = false;
        this.scrollY = 0;
        this.logs = [
            { date: "12th April 2026", entries: [
                "- Completed buttons UI design",
                "- Finish mob gallery UI drawing",
                "- Added flowing petals in main menu"
            ]},
            { date: "11th April 2026", entries: [
                "- Battery body lightning: 69.",
                "- Fixed Warp not teleporting.",
                "- New map UI and better setting"
            ]},
            { date: "9th April 2026", entries: [
                "- Battery flower body lightning: 120 -> 100.",
                "- Dizzy, Wound, Puppeteer, Elemental now increase fire & poison damage.",
                "- Amulet now allows all eggs to spawn."
            ]},
            { date: "7th April 2026", entries: [
                "- Added new Hel biome with 15+ new enemies.",
                "- Added spacetime tunnel system.",
                "- Improved performance with chunk-based loading.",
                "- Fixed petal rotation issues."
            ]},
            { date: "5th April 2026", entries: [
                "- New item: Opal (crit chance & damage).",
                "- Added hunting quest system.",
                "- Added mob gallery.",
                "- Balance changes: reduced boss spawn rates."
            ]},
            { date: "3rd April 2026", entries: [
                "- Add Void and micro world",
                "- Add SpacetimeTunnel",

            ]},
            { date: "1st April 2026", entries: [
                "- changelog are not available before"
            ]}
        ];
        this.panelW = 420;
        this.panelH = 460;
        this.closeRect = null;
        this.totalContentH = 0;
    }

    draw(ctx) {
        if (!this.visible) return;
        const px = WIDTH - 1300 - this.panelW / 2;
        const py = HEIGHT - 550 - this.panelH / 2;

        // --- 背景 ---
        ctx.fillStyle = '#4caf50';
        ctx.beginPath();
        ctx.roundRect(px, py, this.panelW, this.panelH, 12);
        ctx.fill();
        ctx.strokeStyle = '#2e7d32';
        ctx.lineWidth = 4;
        ctx.lineJoin = 'round';
        ctx.stroke();

        // --- 标题位置修正 (加大号字体) ---
        const titleX = px + this.panelW / 2;
        const titleY = py + 35; // 稍微下移一点点以适应大字

        ctx.font = 'bold 28px Arial'; // 22px -> 28px
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.lineJoin = 'round';

        ctx.lineWidth = 5;
        ctx.strokeStyle = '#000000';
        ctx.strokeText('Changelog', titleX, titleY);
        ctx.fillStyle = '#ffffff';
        ctx.fillText('Changelog', titleX, titleY);

        // --- 关闭按钮 ---
        this.closeRect = [px + this.panelW - 50, py + 12, 38, 38]; // 稍微加宽一点
        ctx.fillStyle = '#f44336';
        ctx.beginPath();
        ctx.roundRect(...this.closeRect, 8);
        ctx.fill();

        ctx.font = 'bold 22px Arial'; // 按钮文字加大
        ctx.strokeStyle = '#000000';
        ctx.lineWidth = 3;
        ctx.strokeText('✕', px + this.panelW - 31, py + 31);
        ctx.fillStyle = '#ffffff';
        ctx.fillText('✕', px + this.panelW - 31, py + 31);

        // --- 内容区 ---
        const contentY = py + 70; // 标题变大，起始位下移
        const contentH = this.panelH - 85;
        ctx.save();
        ctx.beginPath();
        ctx.rect(px + 10, contentY, this.panelW - 20, contentH);
        ctx.clip();

        let y = contentY + 10 - this.scrollY;
        ctx.textAlign = 'left';

        const drawTextWithStroke = (text, x, y, fontSize, fontWeight = 'normal') => {
            ctx.font = `${fontWeight} ${fontSize}px Arial`;
            ctx.textBaseline = 'top';
            ctx.lineJoin = 'round';
            ctx.strokeStyle = '#000000';
            ctx.lineWidth = 3; // 粗描边更有圆润感
            ctx.strokeText(text, x, y);
            ctx.fillStyle = '#ffffff';
            ctx.fillText(text, x, y);
        };

        for (let i = 0; i < this.logs.length; i++) {
            const group = this.logs[i];

            // 日期标题 (加大到 22px)
            drawTextWithStroke(group.date, px + 16, y, 22, 'bold');
            y += 32;

            // 条目内容 (加大到 18px)
            for (const entry of group.entries) {
                const words = entry.split(' ');
                let line = '';
                // 预设字体以便测量
                ctx.font = '18px Arial';

                for (const word of words) {
                    const test = line + word + ' ';
                    // 增加边距感，宽度检测设为 panelW - 40
                    if (ctx.measureText(test).width > this.panelW - 40 && line) {
                        drawTextWithStroke(line, px + 16, y, 18);
                        y += 24; // 行间距加大
                        line = word + ' ';
                    } else {
                        line = test;
                    }
                }
                if (line) {
                    drawTextWithStroke(line.trim(), px + 16, y, 18);
                    y += 24;
                }
                y += 6; // 段间距
            }

            // 分隔线
            if (i < this.logs.length - 1) {
                ctx.strokeStyle = '#388e3c';
                ctx.lineWidth = 2;
                ctx.beginPath();
                ctx.moveTo(px + 15, y + 8);
                ctx.lineTo(px + this.panelW - 15, y + 8);
                ctx.stroke();
                y += 24;
            }
        }

        this.totalContentH = y + this.scrollY - contentY;
        ctx.restore();
    }

    handleClick(x, y) {
        if (!this.visible) return false;

        const canvas = document.getElementById('gameCanvas');
        if (!canvas) return false;

        const px = canvas.width / 2 - this.panelW / 2;
        const py = canvas.height / 2 - this.panelH / 2;

        // 点击面板外关闭
        if (x < px || x > px + this.panelW || y < py || y > py + this.panelH) {
            this.visible = false;
            return true;
        }

        // 关闭按钮
        if (this.closeRect) {
            const [cx, cy, cw, ch] = this.closeRect;
            if (x >= cx && x <= cx + cw && y >= cy && y <= cy + ch) {
                this.visible = false;
                return true;
            }
        }

        return true; // 在面板内，拦截点击
    }

    handleWheel(deltaY) {
        if (!this.visible) return false;

        const maxScroll = Math.max(0, (this.totalContentH || 0) - (this.panelH - 70));
        this.scrollY = Math.max(0, Math.min(maxScroll, this.scrollY + deltaY));
        return true;
    }
    handleScroll(deltaY) {
            if (!this.visible) return false;

            const contentH = this.panelH - 70;
            const maxScroll = Math.max(0, (this.totalContentH || 0) - contentH);

            // 滚动速度调整（deltaY 正值向下滚动）
            const scrollAmount = deltaY * 0.8;
            this.scrollY = Math.max(0, Math.min(maxScroll, this.scrollY + scrollAmount));

            return true;
        }
    open() {
        this.visible = true;
        this.scrollY = 0;
    }

    close() {
        this.visible = false;
    }

    toggle() {
        this.visible = !this.visible;
        if (this.visible) this.scrollY = 0;
    }
}
