        const hornetY = Math.max(100, Math.min(WORLD_HEIGHT - 100, baseY + Math.sin(angleHornet) * distanceHornet));

        const helHornet = new Enemy("HelHornet", hornetX, hornetY, this.level, this.rarity);
        helHornet.spawnTime = Date.now();
