    updateCollisionPositions() {
        for (const [enemy, enemyId] of this.enemyToId.entries()) {
            if (enemy.physicsBody && enemy.health > 0) {
                const x = enemy.physicsBody.position.x;
                const y = enemy.physicsBody.position.y;
                this.collisionSystem.updateObject(enemyId, x, y);
            }
        }
    }
    precomputeWallBoxes(biome) {
        console.log(`🔍 开始预计算 ${biome} 墙壁边界框...`);

        const bgConfig = BIOME_BACKGROUNDS[biome];
        if (!bgConfig || !bgConfig.map || !bgConfig.map.image) return;

        const mapImageKey = bgConfig.map.image;
        const mapImg = window.imageLoader?.getImage(mapImageKey);
        if (!mapImg || !mapImg.width) return;

        // ✅ 降采样到固定尺寸，大幅减少像素数量
        const SAMPLE_SIZE = 256;   // 原来用原图尺寸，可能高达 1000+
        const canvas = document.createElement('canvas');
        canvas.width  = SAMPLE_SIZE;
        canvas.height = SAMPLE_SIZE;
        const ctx = canvas.getContext('2d');
        ctx.drawImage(mapImg, 0, 0, SAMPLE_SIZE, SAMPLE_SIZE);

        let data;
        try {
            data = ctx.getImageData(0, 0, SAMPLE_SIZE, SAMPLE_SIZE).data;
        } catch (e) {
            console.error(`❌ 无法读取 ${biome} 像素数据:`, e);
            return;
        }

        const W = SAMPLE_SIZE, H = SAMPLE_SIZE;

        // ✅ 用 Uint8Array 替代二维布尔数组，内存节省 ~8 倍
        const wallMap   = new Uint8Array(W * H);
        const processed = new Uint8Array(W * H);

        for (let y = 0; y < H; y++) {
            for (let x = 0; x < W; x++) {
                const i = (y * W + x) * 4;
                if (data[i + 3] < 128) continue;           // 透明
                if ((data[i] + data[i+1] + data[i+2]) / 3 < 128) {
                    wallMap[y * W + x] = 1;                // 深色 = 墙壁
                }
            }
        }

        const boxes   = [];
        const MIN_PIX = 2;   // 降采样后最小合并尺寸（对应原图约 8px）

        for (let y = 0; y < H; y++) {
            for (let x = 0; x < W; x++) {
                const idx = y * W + x;
                if (!wallMap[idx] || processed[idx]) continue;

                // 找最大宽度
                let w = 0;
                while (x + w < W && wallMap[y * W + x + w] && !processed[y * W + x + w]) w++;

                // 找最大高度
                let h = 1;
                outer: for (; y + h < H; h++) {
                    for (let dx = 0; dx < w; dx++) {
                        const ni = (y + h) * W + x + dx;
                        if (!wallMap[ni] || processed[ni]) break outer;
                    }
                }

                if (w >= MIN_PIX || h >= MIN_PIX) {
                    // 标记已处理
                    for (let dy = 0; dy < h; dy++)
                        for (let dx = 0; dx < w; dx++)
                            processed[(y + dy) * W + x + dx] = 1;

                    boxes.push({
                        x:      (x / W) * WORLD_WIDTH,
                        y:      (y / H) * WORLD_HEIGHT,
                        width:  (w / W) * WORLD_WIDTH,
                        height: (h / H) * WORLD_HEIGHT
                    });
                }
            }
        }

        this.wallCache.set(biome, { boxes, imgWidth: W, imgHeight: H });
        console.log(`✅ ${biome} 墙壁边界框预计算完成: ${boxes.length} 个矩形`);
    }

    drawWallBoxes(context, cameraOffset) {
        const cache = this.wallCache.get(this.currentBiome);
        if (!cache || !cache.boxes) return;

        const bgConfig = BIOME_BACKGROUNDS[this.currentBiome];
        const wallColor = bgConfig.wall_color || [100, 100, 100];

        // 可选：如果你有专门的边框颜色配置
        const hasBorder = bgConfig.wall_border_color !== undefined;
        const borderColor = hasBorder ? bgConfig.wall_border_color : [wallColor[0]-40, wallColor[1]-40, wallColor[2]-40];

        const left = cameraOffset.x;
        const right = cameraOffset.x + WIDTH;
        const top = cameraOffset.y;
        const bottom = cameraOffset.y + HEIGHT;

        const boxes = cache.boxes;

        // --- 第一步：绘制填充 ---
        context.fillStyle = `rgb(${wallColor[0]}, ${wallColor[1]}, ${wallColor[2]})`;
        context.beginPath(); // 开始一个新路径，批量绘制以提高性能

        for (let i = 0; i < boxes.length; i++) {
            const box = boxes[i];

            // 视锥剔除 (Culling)
            if (box.x + box.width < left || box.x > right ||
                box.y + box.height < top || box.y > bottom) {
                continue;
            }

            const x = Math.floor(box.x - cameraOffset.x);
            const y = Math.floor(box.y - cameraOffset.y);
            const w = Math.ceil(box.width) + 1;   // +1 填补缝隙
            const h = Math.ceil(box.height) + 1;  // +1 填补缝隙

            // 确保最小尺寸为 1，防止消失
            if (w === 0 || h === 0) continue;

            context.rect(x, y, w, h);
        }
        context.fill();

        // --- 第二步：绘制描边 (如果需要) ---
        if (hasBorder) {
            context.strokeStyle = `rgb(${borderColor[0]}, ${borderColor[1]}, ${borderColor[2]})`;
            context.lineWidth = 2;

            // ⚠️ 注意：直接 stroke() 会导致相邻方块之间的线变粗（画了两次）
            // 对于由小方块组成的地图，完美的外轮廓描边需要复杂的几何合并算法。
            // 妥协方案：接受内部线条稍粗，或者只在不重叠的地方画。

            // 这里我们简单地再次遍历绘制描边，虽然内部会重叠，但性能最好
            context.beginPath();
            for (let i = 0; i < boxes.length; i++) {
                const box = boxes[i];
                if (box.x + box.width < left || box.x > right ||
                    box.y + box.height < top || box.y > bottom) continue;

                const x = Math.round(box.x - cameraOffset.x);
                const y = Math.round(box.y - cameraOffset.y);
                const w = Math.round(box.width);
                const h = Math.round(box.height);

                if (w === 0 || h === 0) continue;

                // 绘制单个矩形的描边
                // 为了避免内部线条过粗，可以将 lineWidth 设得很小，或者依赖填充色的对比度
                context.rect(x, y, w, h);
            }
            context.stroke();
        }
    }

    checkCollisions() {
        this.updateCollisionPositions();
        const collisions = this.collisionSystem.checkAllCollisions();
        for (const [obj1Id, obj2Id] of collisions) {
            const obj1 = this.idToEnemy.get(obj1Id);
            const obj2 = this.idToEnemy.get(obj2Id);
            if (obj1 && obj2) {
                this.handleCollision(obj1, obj2);
            }
        }
    }

